namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh tomatoes, mozzarella, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, egg, and Pecorino Romano.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with pancetta.", "Remove from heat and stir in egg mixture quickly.", "Serve immediately with extra cheese."],
                TotalRatings = 8, RatingSum = 36
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or bake chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and spices, simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice or naan."],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with vegetables, peanuts, and tangy sauce.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Carrots", "Green onions", "Peanuts", "Pad Thai sauce", "Lime"],
                Steps = ["Soak rice noodles in warm water for 30 minutes.", "Press and cube tofu, then pan-fry until golden.", "Stir-fry carrots and bean sprouts.", "Add noodles and Pad Thai sauce.", "Toss everything together.", "Serve topped with peanuts, green onions, and lime wedges."],
                TotalRatings = 6, RatingSum = 25
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in crispy tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa.", "Serve immediately."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, chunky guacamole with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, tomato, and jalapeño.", "Add lime juice and chopped cilantro.", "Season with salt to taste.", "Serve with tortilla chips."],
                TotalRatings = 9, RatingSum = 40
            },
            new Recipe
            {
                Id = 7, Title = "Tom Yum Soup", Category = "Thai",
                Description = "Hot and sour Thai soup with shrimp and mushrooms.",
                Ingredients = ["Shrimp", "Mushrooms", "Lemongrass", "Galangal", "Kaffir lime leaves", "Fish sauce", "Lime juice", "Chili paste"],
                Steps = ["Bring broth to a boil with lemongrass, galangal, and lime leaves.", "Add mushrooms and cook 3 minutes.", "Add shrimp and chili paste.", "Cook until shrimp turn pink.", "Season with fish sauce and lime juice.", "Serve hot, garnished with cilantro."],
                TotalRatings = 7, RatingSum = 31
            },
            new Recipe
            {
                Id = 8, Title = "Palak Paneer", Category = "Indian",
                Description = "Creamy spinach curry with soft paneer cheese cubes.",
                Ingredients = ["Spinach", "Paneer", "Onion", "Garlic", "Ginger", "Green chili", "Cream", "Cumin seeds"],
                Steps = ["Blanch spinach and blend into a purée.", "Sauté cumin seeds, onion, garlic, ginger, and green chili.", "Add spinach purée and simmer.", "Cut paneer into cubes and add to the sauce.", "Stir in cream and cook 5 minutes.", "Serve with naan or rice."],
                TotalRatings = 5, RatingSum = 22
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title.Trim(),
            Category = category.Trim(),
            Ingredients = ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

