@page "/"
@using RecipeHub.Services

<PageTitle>RecipeHub — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍽️ RecipeHub</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-4 g-4 mt-2">
    @foreach (var category in Categories)
    {
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h3 class="card-title">@GetEmoji(category) @category</h3>
                    <p class="card-text text-muted">
                        @GetRecipeCount(category) recipe(s)
                    </p>
                    <a href="category/@category" class="btn btn-outline-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private int GetRecipeCount(string category) =>
        RecipeService.GetByCategory(category).Count;

    private string GetEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        _ => "🍴"
    };
}

@page "/category/{CategoryName}"
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted mb-2">
                            @if (recipe.TotalRatings > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<div class="mt-4">
    <a href="/" class="btn btn-outline-secondary">← Back to Categories</a>
</div>

