    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: <a href="category/@Recipe.Category">@Recipe.Category</a></p>
    <p class="lead">@Recipe.Description</p>

    <div class="row mt-4">
