@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services

<div>
    <span class="fs-4">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  style="cursor: pointer; color: @(star <= DisplayRating ? "#ffc107" : "#e0e0e0")"
                  @onclick="() => Rate(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = 0">
                ★
            </span>
        }
    </span>

    @if (HasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }

    @if (CurrentAverage > 0)
    {
        <span class="ms-2 text-muted">
            Avg: @CurrentAverage.ToString("F1") (@CurrentTotal ratings)
        </span>
    }
</div>

@code {
    [Parameter, EditorRequired] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private int HoverRating { get; set; }
    private int SelectedRating { get; set; }
    private bool HasRated { get; set; }
    private double CurrentAverage { get; set; }
    private int CurrentTotal { get; set; }

    private int DisplayRating => HoverRating > 0 ? HoverRating : SelectedRating;

    protected override void OnInitialized()
    {
        RefreshStats();
    }

    private void Rate(int stars)
    {
        if (HasRated) return;

        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        HasRated = true;
        RefreshStats();
    }

    private void RefreshStats()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            CurrentTotal = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@using Microsoft.AspNetCore.Components.Forms

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="lead">Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added.</p>
        <a href="recipe/@SubmittedRecipeId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputText id="category" class="form-control" @bind-Value="Model.Category" placeholder="e.g., Italian, Indian, Thai, Mexican" />
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, sliced" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int SubmittedRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(Model.Title, Model.Category, Model.Ingredients, Model.Steps);
        SubmittedRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new();
        Submitted = false;
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string Steps { get; set; } = string.Empty;
    }
}

